// Compile the Morning Brief from agent memory (repo mounted read-only at /data/swingby).
const fs = require('fs');
const read = (p) => { try { return fs.readFileSync(p, 'utf8'); } catch (e) { return ''; } };
const MEM = '/data/swingby/AGENTS/claude/memory/';

const status = read(MEM + 'STATUS.md');
const todo   = read(MEM + 'HUMAN-TODO.md');
const slog   = read(MEM + 'SESSION_LOG.md');
const onlog  = read('/data/swingby/AGENTS/claude/automation/overnight.log');

// Grab the body of a '## Heading' section.
const section = (src, heading) => {
  const esc = heading.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const m = new RegExp('^## .*' + esc + '.*$', 'm').exec(src);
  if (!m) return '';
  const rest = src.slice(m.index + m[0].length);
  const next = rest.search(/^## /m);
  return (next === -1 ? rest : rest.slice(0, next)).trim();
};

const blockers = section(todo, 'Blocking')
  .split('\n')
  .filter((l) => l.startsWith('- [ ]'))
  .map((l) => l.replace(/^- \[ \] \*\*(.+?)\*\*.*$/, '• $1').slice(0, 160));

const loopNext = (slog.match(/^NEXT:.*$/gm) || []).pop() || '';
const overnightTail = onlog
  ? onlog.trim().split('\n').slice(-8).join('\n')
  : '(overnight loop did not run)';

const today = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Edmonton' });
const brief = [
  '☀️ SWINGBY MORNING BRIEF — ' + today,
  '',
  'SIGNAL: ' + (section(status, 'Session End Signal') || 'no signal — read STATUS.md'),
  '',
  '— NEXT ACTIONS (STATUS) —',
  section(status, 'Next Action') || '(none recorded)',
  '',
  '— BLOCKING, ONLY YOU (HUMAN-TODO) —',
  blockers.length ? blockers.join('\n') : '(clear)',
  '',
  '— OVERNIGHT LOOP (log tail) —',
  overnightTail,
  '',
  loopNext ? 'LOOP ' + loopNext : ''
].join('\n').trim();

return [{ json: { brief: brief.slice(0, 3900) } }];
